    val bannerViewModel: BannerViewModels = viewModel()
    val context = LocalContext.current

    // Get current value
    var currentSelectedIndex by rememberSaveable {
        mutableIntStateOf(
            navController?.currentBackStackEntry?.savedStateHandle?.get<Int>("currentSelectedIndex")
                ?: selectedTabIndex
        )
    }

    // Track recently selected tabs from "See All" page
    var recentlySelectedTabs by rememberSaveable { mutableStateOf(listOf<Int>()) }

    // Save changes back to savedStateHandle
    LaunchedEffect(currentSelectedIndex) {
        navController?.currentBackStackEntry?.savedStateHandle?.set(
            "currentSelectedIndex",
            currentSelectedIndex
        )
    }

    Log.d("CategoryTabsFood", "currentSelectedIndex in CategoryTabsFood: $currentSelectedIndex")

    val savedDietTabIndex = remember(navController?.currentBackStackEntry) {
        navController?.currentBackStackEntry?.savedStateHandle?.get<Int>("dietTabIndex")
            ?: 0
    }

    // Update when parent state changes
    LaunchedEffect(selectedTabIndex) {
        currentSelectedIndex = selectedTabIndex
    }

    // Get all category pages and filter only active ones, then sort by priority
  val allCategoryPages = listOf(
    CategoryPage.All,
    CategoryPage.Diet,
    CategoryPage.Pizzas,
    CategoryPage.Cakes,
    CategoryPage.Momos,
    CategoryPage.Rolls,
    CategoryPage.Burgers,
    CategoryPage.CholeBhature,
    CategoryPage.Salad,
    CategoryPage.Patty,
    CategoryPage.Chinese,
    CategoryPage.IceCream,
    CategoryPage.Appam,
    CategoryPage.Bath,
    CategoryPage.Bonda,
    CategoryPage.Cutlet,
    CategoryPage.Dessert,
    CategoryPage.Dhokla,
    CategoryPage.Dosa,
    CategoryPage.Dholda,
    CategoryPage.GulabJamun,
    CategoryPage.Idli,
    CategoryPage.Biryani,
    CategoryPage.Thali,
    CategoryPage.Chicken,
    CategoryPage.VegMeal,
    CategoryPage.NorthIndian,
    CategoryPage.Paneer,
    CategoryPage.FriedRice,
    CategoryPage.Noodles,
    CategoryPage.Paratha,
    CategoryPage.Shawarma,
    CategoryPage.SouthIndian,
    CategoryPage.AlooTikki,
    CategoryPage.Pasta,
    CategoryPage.Pastry,
    CategoryPage.PavBhaji,
    CategoryPage.Sandwich,
    CategoryPage.Shake,
    CategoryPage.Samosa,
    CategoryPage.Poori,
    CategoryPage.Bowl,
    CategoryPage.Poha,
    CategoryPage.Sweets,
    CategoryPage.CholePoori,
    CategoryPage.Khichdi,
    CategoryPage.ChilliChicken,
    CategoryPage.Tea,
    CategoryPage.VadaPav,
    CategoryPage.MasalaMaggi,
    CategoryPage.Kulche,
    CategoryPage.Wings,
    CategoryPage.AlooPoori,
    CategoryPage.Omelette,
    CategoryPage.NonVegMeal,
    CategoryPage.BreadPakoda,
    CategoryPage.Coffee,
    CategoryPage.PooriBhaji,
    CategoryPage.Pulao,
    CategoryPage.ChurChurNaan,
    CategoryPage.Kebabs,
    CategoryPage.Panipuri,
    CategoryPage.Rasmalai,
    CategoryPage.Mutton,
    CategoryPage.Fish,
    CategoryPage.Pakoda,
    CategoryPage.Halwa,
    CategoryPage.ChopSuey,
    CategoryPage.Korma,
    CategoryPage.Namkeen,
    CategoryPage.Mushrooms,
    CategoryPage.Keema,
    CategoryPage.Sundae,
    CategoryPage.Rasgulla,
    CategoryPage.ButterChicken,
    CategoryPage.RajKachori,
    CategoryPage.Chaat,
    CategoryPage.Uttapam,
    CategoryPage.Doughnut,
    CategoryPage.Juice,
    CategoryPage.Lassi,
    CategoryPage.MalaiKofta,
    CategoryPage.DahiBalle,
    CategoryPage.Rajma,
    CategoryPage.ChickenHandi,
    CategoryPage.Cupcake,
    CategoryPage.Bhel,
    CategoryPage.Muffin,
    CategoryPage.Cookies,
    CategoryPage.ChickenCha,
    CategoryPage.PaneerKulche,
    CategoryPage.Chaach,
    CategoryPage.VegLollipop,
    CategoryPage.Sub,
    CategoryPage.Pancake,
    CategoryPage.Nihari,
    CategoryPage.Tacos,
