                                error = androidx.compose.ui.res.painterResource(id = R.drawable.placeholder_food)
                            ),
                            contentDescription = categoryPage.title,
                            modifier = Modifier
                                .width(65.dp)
                                .height(45.dp),
                            contentScale = ContentScale.FillBounds
                        )

                        Text(
                            text = categoryPage.title,
                            fontSize = 15.sp,
                            fontWeight = if (isSelected) FontWeight.Bold else FontWeight.Medium,
                            color = if (isSelected) {
                                MaterialTheme.customColors.header
                            } else {
                                MaterialTheme.customColors.black
                            },
                            maxLines = 2,
                            textAlign = TextAlign.Center,
                            overflow = TextOverflow.Ellipsis,
                            modifier = Modifier.padding(top = 4.dp)
                        )

                        // Show a small indicator for recently added tabs
                        if (!isSeeAllTab && allCategoriesIndex >= initialVisibleCount) {
                            Box(
                                modifier = Modifier
                                    .padding(top = 2.dp)
                                    .size(6.dp)
                                    .clip(CircleShape)
                                    .background(MaterialTheme.customColors.header.copy(alpha = 0.6f))
                            )
                        }
                    }
                }
            }
        }

        // Show content for each tab
        Column(
            modifier = Modifier
