@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun AllCategoryPage(
    navController: NavHostController? = null,
    viewModel: BannerViewModels = viewModel(),
    restaurantViewModel: RestaurantViewModel = viewModel(),
    superCategoryId: String = "FOOD_SUPER",
    categoryId: String = "ALL_FOOD_CAT",
    onBanner1Click: () -> Unit = {},
    onBanner2Click: () -> Unit = {},
    onBanner3Click: () -> Unit = {}
) {
    // Collect restaurant state - using featured and recommended APIs
    val featuredRestaurants by restaurantViewModel.featuredRestaurants.collectAsState()
    val recommendedRestaurants by restaurantViewModel.recommendedRestaurants.collectAsState()
    val isRestaurantsLoading by restaurantViewModel.isLoading.collectAsState()
    val restaurantError by restaurantViewModel.error.collectAsState()

    // Load featured restaurants from API
    LaunchedEffect(Unit) {
        println("🚀 Loading FEATURED restaurants from API for category: ALL")
        restaurantViewModel.loadFeaturedRestaurants("ALL", featured = true)
        restaurantViewModel.loadRecommendedRestaurants("ALL", recommended = true)
    }

    // Collect healthy score banners
    val healthyScoreBanners by viewModel.healthyScoreBanners.collectAsState()

    // Load healthy score banners when composable is first created
    LaunchedEffect(Unit) {
        viewModel.loadHealthyScoreBanners()
    }

    // Create banner images data for healthy score
    val healthyScoreBannerImagesData by remember(healthyScoreBanners) {
        derivedStateOf {
            healthyScoreBanners.mapNotNull { banner ->
                val fullUrl = banner.imageUrl?.let { url ->
                    when {
                        url.startsWith("http") -> url
                        url.startsWith("/") -> "${NetworkConfig.BASE_URL}$url"
                        else -> "${NetworkConfig.BASE_URL}/$url"
                    }
                }
                fullUrl?.let { BannerImageData.Remote(url = it) }
            }
        }
    }

    fun trackBannerClick(banner: Banner) {
        println("🎯 Banner clicked: ${banner.title} (ID: ${banner.id}, Type: ${banner.bannerType})")
    }

    // Collect state from ViewModel
    val allBanners by viewModel.bannersByCategory.collectAsState()
    val isLoading by viewModel.isLoading.collectAsState()
    val error by viewModel.error.collectAsState()

    // Load banners when composable is first created
    LaunchedEffect(superCategoryId, categoryId) {
        println("🚀 Initializing AllCategoryPage with superCategory: $superCategoryId, category: $categoryId")
        viewModel.loadBannersBySuperCategoryAndCategory(
            superCategoryId = superCategoryId,
            categoryId = categoryId,
            page = 0,
            size = 20
        )
    }

    // Clean up when composable is disposed
    DisposableEffect(Unit) {
        onDispose {
            println("🧹 Cleaning up AllCategoryPage")
            viewModel.clearError()
            restaurantViewModel.clearError()
        }
    }

    // Filter only banners with valid image URLs
    val validBanners by remember(allBanners) {
        derivedStateOf {
            allBanners.filter { banner ->
                banner.imageUrl.isNullOrBlank().not()
            }.also { filtered ->
                println("✅ Found ${filtered.size} valid banners out of ${allBanners.size} total")
            }
        }
    }

    val bannerImagesData by remember(validBanners) {
        derivedStateOf {
            validBanners.mapNotNull { banner ->
                val fullUrl = banner.imageUrl?.let { url ->
                    when {
                        url.startsWith("http") -> url
                        url.startsWith("/") -> "${NetworkConfig.BASE_URL}$url"
                        else -> "${NetworkConfig.BASE_URL}/$url"
                    }
                }
                fullUrl?.let { BannerImageData.Remote(url = it) }
            }
        }
    }



    // Main Column with vertical scroll
    Column(
        modifier = Modifier
            .fillMaxSize()
            .background(Color.White)
    ) {

        // ==================== DYNAMIC BANNER FROM API ====================
        when {
            isLoading -> {
                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .height(200.dp)
                        .padding(12.dp),
                    contentAlignment = Alignment.Center
                ) {
                    Column(
                        horizontalAlignment = Alignment.CenterHorizontally,
                        verticalArrangement = Arrangement.Center
                    ) {
                        CircularProgressIndicator(
                            color = MaterialTheme.colorScheme.primary,
                            modifier = Modifier.size(40.dp)
                        )
                        Spacer(modifier = Modifier.height(8.dp))
                        Text(
                            text = "Loading banners...",
                            fontSize = 12.sp,
                            color = Color.Gray
                        )
                    }
                }
            }

            error != null -> {
                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .height(200.dp)
                        .padding(12.dp),
                    contentAlignment = Alignment.Center
                ) {
                    Card(
                        modifier = Modifier.fillMaxSize(),
                        colors = CardDefaults.cardColors(
                            containerColor = Color(0xFFFFF3E0)
                        ),
                        shape = RoundedCornerShape(16.dp)
                    ) {
                        Column(
                            modifier = Modifier
                                .fillMaxSize()
                                .padding(16.dp),
                            horizontalAlignment = Alignment.CenterHorizontally,
                            verticalArrangement = Arrangement.Center
                        ) {
                            Icon(
                                imageVector = Icons.Default.Error,
                                contentDescription = "Error",
                                tint = Color.Red,
                                modifier = Modifier.size(48.dp)
                            )
                            Spacer(modifier = Modifier.height(12.dp))
                            Text(
                                text = "Failed to load banners",
                                color = Color.Red,
                                fontSize = 16.sp,
                                fontWeight = FontWeight.Bold
                            )
                            Text(
                                text = error ?: "Unknown error occurred",
                                color = Color.Red.copy(alpha = 0.7f),
                                fontSize = 12.sp,
                                modifier = Modifier.padding(top = 4.dp),
                                textAlign = TextAlign.Center
                            )
                            Spacer(modifier = Modifier.height(16.dp))
                            Button(
                                onClick = {
                                    println("🔄 Retrying banner load...")
                                    viewModel.loadBannersBySuperCategoryAndCategory(
                                        superCategoryId = superCategoryId,
                                        categoryId = categoryId
                                    )
                                },
                                colors = ButtonDefaults.buttonColors(
                                    containerColor = MaterialTheme.colorScheme.primary
                                ),
                                modifier = Modifier.height(36.dp)
                            ) {
                                Text("Retry", fontSize = 14.sp)
                            }
                        }
                    }
                }
            }

            bannerImagesData.isNotEmpty() -> {
                println("🎨 Rendering dynamic banner with ${bannerImagesData.size} images")
                DynamicBannerWithAsyncImage(
                    images = bannerImagesData,
                    onImageClick = { page ->
                        val banner = validBanners.getOrNull(page)
                        if (banner != null) {
                            println("🖱️ Banner clicked at index $page: ${banner.title}")
                            trackBannerClick(banner)

                            when (banner.bannerType) {
                                "HOME_PAGE" -> {
                                    println("🏠 Navigating to home page")
                                    onBanner1Click()
                                }
                                "PROMOTIONAL" -> {
                                    println("🎉 Navigating to promotional page")
                                    onBanner2Click()
                                }
                                "FLASH_SALE" -> {
                                    println("⚡ Navigating to flash sale")
                                    onBanner3Click()
                                }
                                else -> {
                                    banner.clickUrl?.let { url ->
                                        println("🔗 Navigating to URL: $url")
                                    }
                                }
                            }
                        } else {
                            println("⚠️ No banner found for index $page")
                        }
                    },
                    autoScrollDelay = 3000,
                    height = 200.dp,
                    roundedCornerShape = 16.dp,
                    contentScale = ContentScale.Crop,
                    dotSize = 8.dp,
                    dotPadding = 4.dp,
                    dotPosition = DotPosition.OVERLAY,
                    overlayGradient = false,
                    selectedDotColor = Color.White,
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(horizontal = 12.dp, vertical = 12.dp),
                    padding = BannerPadding(
                        start = 0.dp,
                        top = 0.dp,
                        end = 0.dp,
                        bottom = 0.dp
                    )
                )
            }

            else -> {
                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .height(200.dp)
                        .padding(12.dp),
                    contentAlignment = Alignment.Center
                ) {
                    Card(
                        modifier = Modifier.fillMaxSize(),
                        colors = CardDefaults.cardColors(
                            containerColor = Color(0xFFF5F5F5)
                        ),
                        shape = RoundedCornerShape(16.dp)
                    ) {
                        Column(
                            modifier = Modifier
                                .fillMaxSize()
                                .padding(16.dp),
                            horizontalAlignment = Alignment.CenterHorizontally,
                            verticalArrangement = Arrangement.Center
                        ) {
                            Box(
                                modifier = Modifier
                                    .size(80.dp)
                                    .background(
                                        Color.LightGray.copy(alpha = 0.3f),
                                        shape = RoundedCornerShape(12.dp)
                                    ),
                                contentAlignment = Alignment.Center
                            ) {
                                Text(
                                    text = "🎯",
                                    fontSize = 40.sp
                                )
                            }
                            Spacer(modifier = Modifier.height(16.dp))
                            Text(
                                text = "No banners available",
                                fontSize = 16.sp,
                                color = Color.Gray,
                                fontWeight = FontWeight.Medium
                            )
                            Spacer(modifier = Modifier.height(8.dp))
                            Text(
                                text = "Check back later for exciting offers!",
                                fontSize = 13.sp,
                                color = Color.Gray.copy(alpha = 0.7f),
                                textAlign = TextAlign.Center
                            )
                        }
                    }
                }
            }
        }

        // ==================== FREE CASH BANNER ====================
        AsyncImage(
            model = "${NetworkConfig.BASE_URL}/assets/banners/ic_use_your_free_cash_auto_applied.png",
            contentDescription = "Free Cash Banner",
            modifier = Modifier
                .fillMaxWidth()
                .heightIn(min = 100.dp, max = 160.dp),
            contentScale = ContentScale.FillBounds
        )

        // ==================== NEW YEAR 2026 SECTION (DYNAMIC) ====================
        val newYearDynamicItems = listOf(
            CategoryItemBgImgDynamic(
                id = 1,
